import{_ as i,o as e,c as o,ae as a}from"./chunks/framework.RRduUuAx.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"szu/marx/chapter-3.md","filePath":"szu/marx/chapter-3.md"}'),r={name:"szu/marx/chapter-3.md"};function u(d,l,c,t,h,n){return e(),o("div",null,[...l[0]||(l[0]=[a('<h2 id="第一节、社会基本矛盾及其运动规律" tabindex="-1">第一节、社会基本矛盾及其运动规律 <a class="header-anchor" href="#第一节、社会基本矛盾及其运动规律" aria-label="Permalink to &quot;第一节、社会基本矛盾及其运动规律&quot;">​</a></h2><p>生产力和生产关系之间的矛盾、经济基础和上层建筑之间的矛盾是<strong>人类社会的基本矛盾。</strong></p><h3 id="一、社会存在与社会意识" tabindex="-1">一、社会存在与社会意识 <a class="header-anchor" href="#一、社会存在与社会意识" aria-label="Permalink to &quot;一、社会存在与社会意识&quot;">​</a></h3><ol><li>社会存在<br> 含义：<code>社会存在是指社会物质生活条件的总和</code>，包括地理环境、人口因素和物质生活资料的生产方式。 <ul><li>地理环境及其在社会发展中的作用：影响和制约作用</li><li>人口因素及其在社会发展中的作用：影响和制约作用</li><li>生产方式及其在社会发展中的作用：<strong>决定作用</strong><br> 生产方式：是人类借以向自然界谋取必需的生活资料的方式，包括生产力和生产关系两个方面，是特定的生产力和生产关系的统一。<br> 生产方式在社会发展中起决定作用，表现在： <ul><li>第一，生产方式是人类从动物界分离出来的根本动力和人类区别于动物的根本标志。</li><li>第二，生产方式是人类和人类社会得以存在和发展的基础</li><li>第三，生产活动是形成人类一切社会关系的基础。生产活动创造了生产关系，在生产关系基础上，又形成社会关系，从而形成了整个人类社会。</li><li>第四，生产方式决定社会制度的性质和社会制度的更替</li></ul></li></ul></li><li>社会意识<br> 含义：是指社会的精神生活过程，它具有复杂而精微的结构，由诸多因素和层次构成。<br> 从不同角度看，可分为三种： <ul><li><code>社会心理和思想体系</code><br> 社会心理是社会意识的低级层次；思想体系是社会意识的高级层次；</li><li>意识形态和非意识形态 <ul><li>意识形态的思想体系，包括政治思想、法律思想、道德、哲学等绝大部分社会科学，他们是上层建筑的重要组成部分。</li><li>非意识形态的思想体系，包括自然科学，语言学，逻辑学等</li></ul></li><li>个体意识和群体意识</li></ul></li><li>社会存在与社会意识的关系 <ul><li>1.社会存在决定社会意识<br> 表现在三个方面：第一，社会意识的内容来源于社会存在。第二，社会意识随着社会存在的发展变化而变化。第三，社会意思受反映者（意识主体）的立场、观点、方法的影响和制约。</li><li>2.社会意识反作用于社会存在<br> 是指社会意识这种精神力量，在一定条件下可以反作用于社会存在，转化为物质力量，影响社会发展的进程。<br> 表现为两种情况： <ul><li>先进的或正确的社会意识对社会存在的发展起积极推动的作用，促进社会向前发展；</li><li>落后的或错误的社会意识对社会存在的发展起消极的阻碍作用，延缓社会的发展进程。<br> 社会意识对社会存在的反作用，必须通过人民群众的实践活动。</li></ul></li><li>3.社会意识的相对独立性<br> 含义：是指社会意识在反映社会存在、被社会存在所决定的同时，还具有自身的能动性和独特性。表现在几个方面： <ul><li>第一，社会意识与社会存在变化发展的非完全同步性</li><li>第二，社会意识与社会经济发展水平具有不平衡性</li><li>第三，社会意识的发展具有历史继承性</li><li>第四，社会意识各种形式之间相互作用、相互影响</li><li>第五，社会意识对社会存在具有反作用或能动性，这是社会意识相对独立性的重要表现</li></ul></li><li>4.历史观的基本问题<br> 社会存在和社会意识的关系问题是历史观的基本问题 <ul><li>首先，社会存在于社会意识包括了人类社会的一切物质现象和精神现象</li><li>其次，社会存在和社会意识的关系问题，是<strong>划分历史唯物主义和历史唯心主义的根本标准</strong></li></ul></li></ul></li></ol><ul><li>[选择题]对社会存在和社会意识关系问题的不同回答是<code>划分历史唯物主义和历史唯心主义的标准</code></li><li>[选择题]在社会存在和社会意识关系问题上，两种根本对立的观点是<code>历史唯物主义和历史唯心主义</code></li></ul><h3 id="二、生产关系必须适合生产力性质的规律" tabindex="-1">二、生产关系必须适合生产力性质的规律 <a class="header-anchor" href="#二、生产关系必须适合生产力性质的规律" aria-label="Permalink to &quot;二、生产关系必须适合生产力性质的规律&quot;">​</a></h3><ol><li>生产力和生产力系统 <ul><li>生产力：是人类利用自然、改造自然、从自然界获取物质资料的能力，生产力范畴反映的是人与自然界的关系。</li><li>生产力系统：生产力的要素或成分，按照一定比例和形式结合起来，形成生产力的整体功能，就构成生产力系统。<br> 现代生产力系统包括 4 类要素：</li><li>独立的实体性因素 <ul><li>包括劳动者、劳动资料、劳动对象</li></ul></li><li><code>运筹性的综合因素</code><ul><li>包括分工协作、经济管理、预测决策等</li></ul></li><li>渗透性因素 <ul><li>主要指自然科学</li></ul></li><li>准备性因素 - 主要指教育<br> 邓小平提出“科学技术是第一生产力”的著名论断。它有三层含义：</li><li>科学渗透于现代生产力系统的各个要素之中</li><li>在现代化生产中，出现了“科学——技术——生产”的过程，使科学对物质生产具有了主导作用和超前作用。</li><li>科学技术已经成为推动生产力发展的重大杠杆</li></ul></li><li>生产关系和生产关系体系 <code>生产关系是指人们在物质生产过程中结成的经济关系。它包括三项内容：1，生产资料的所有制形式；2，人们在生产中的地位及其相互关系；3，产品的分配方式。 </code> 其中生产资料的所有制起决定作用，它是整个生产关系的基础，主要表现在： <ul><li>第一，生产资料所有制形式是生产劳动得以进行的前提</li><li>第二，生产资料所有制形式决定整个生产关系的性质</li><li>第三，生产资料所有制形式决定人们在生产中的地位及其相互关系</li><li>第四，生产资料所有制形式决定产品的分配方式</li></ul></li><li>生产力和生产关系之间的矛盾 <ul><li><code>生产力决定生产关系</code><ul><li><code>生产力的性质决定生产关系的性质</code></li><li><code>生产力的发展决定生产关系的改变</code></li></ul></li><li>生产关系反作用于生产力</li><li>生产力和生产关系之间的矛盾运动</li></ul></li></ol><ul><li>[选择题]衡量生产力水平的客观尺度是<code>生产工具</code></li><li>[选择题]正确说明生产力与生产关系的辩证关系的是<code>生产力的性质决定生产关系的性质</code></li><li>[选择题]人与人的本质是一切社会关系的总和，这强调的是<code>人与人之间的区别</code></li><li>[选择题]人的自然属性指的是<code>人的肉体存在及其特性</code></li><li>[选择题]人区别于动物的根本标志在于<code>制造使用工具</code></li></ul><h3 id="三、上层建筑必须适合经济基础发展要求的规律" tabindex="-1">三、上层建筑必须适合经济基础发展要求的规律 <a class="header-anchor" href="#三、上层建筑必须适合经济基础发展要求的规律" aria-label="Permalink to &quot;三、上层建筑必须适合经济基础发展要求的规律&quot;">​</a></h3><ol><li>经济基础 <ul><li>经济基础是指一个社会中占统治地位的生产关系各个方面的总和，即生产资料所有制形式、各种不同的社会集团在生产中的地位及其相互关系、产品分配方式三个方面的总和。</li></ul></li><li>上层建筑 <ul><li>上层建筑是与经济基础相对应的范畴，指社会的政治、法律、艺术、道德、宗教、哲学等意识形态以及与这些意识形态相适应的政治法律制度和设施的总和。</li><li>分为政治上层建筑和观念上层建筑 <ul><li>政治上层建筑：政治法律制度以及军队、警察、法院、监狱、政府机关等设施。</li><li>观念上层建筑：政治、法律、艺术、道德、宗教、哲学</li></ul></li></ul></li><li>经济基础与上层建筑之间的矛盾 <ul><li>经济基础决定上层建筑</li><li>上层建筑反作用于经济基础</li><li>经济基础和上层建筑之间的矛盾运动</li></ul></li></ol><h3 id="四、社会形态的划分和社会形态的更替与发展" tabindex="-1">四、社会形态的划分和社会形态的更替与发展 <a class="header-anchor" href="#四、社会形态的划分和社会形态的更替与发展" aria-label="Permalink to &quot;四、社会形态的划分和社会形态的更替与发展&quot;">​</a></h3><ol><li>社会形态的划分<br> 经济社会形态是直接或间接以生产关系的性质为标准划分的社会形态。 <ul><li>经济社会形态划分法：又分两种（五种社会形态划分法、三种社会形态划分法） <ul><li>五种：原始社会，奴隶社会，封建社会，资本主义社会，共产主义社会</li><li>三种：人的依赖社会、物的依赖社会、个人全面发展的社会</li></ul></li><li>技术社会形态划分法（以生产力和技术发展水平以及与此相适应的行业结构划分） <ul><li><code>渔猎社会，农业社会，工业社会，信息社会</code></li></ul></li></ul></li><li>社会形态的发展是自然历史过程<br> 社会发展具有不以人的意志为转移的客观实在</li><li>社会历史发展具有决定性与选择性<br> 决定性是指历史决定论，社会历史发展的选择性是指主体选择的作用</li><li>社会形态发展具有统一性和多样性 <ul><li>统一性是指处于同一社会形态的不同国家和民族的历史发展具有共同性、普遍性。</li><li>多样性是指不同国家和名族发展具有不同的特点，有自己的特色。 <ul><li>1.处于同一社会形态的不同国家和不同名族的历史具有各自的特点。</li><li>2.各个国家在不同的社会形态中所具有的典型意义不同</li><li>3.人类社会在由较低的社会形态向较高的社会形态转变时，不同国家和民族采取的过渡形式各有特点。</li><li>4.有些国家和民族由于特殊的社会历史条件，在社会形态转变过程中，可能超越某一个或某几个社会形态。</li></ul></li></ul></li></ol><ul><li>[选择题]下列属于技术社会形态序列的是<code>信息社会</code></li></ul><h2 id="第二节、社会历史发展的动力" tabindex="-1">第二节、社会历史发展的动力 <a class="header-anchor" href="#第二节、社会历史发展的动力" aria-label="Permalink to &quot;第二节、社会历史发展的动力&quot;">​</a></h2><h3 id="一、社会基本矛盾在社会发展中的作用" tabindex="-1">一、社会基本矛盾在社会发展中的作用 <a class="header-anchor" href="#一、社会基本矛盾在社会发展中的作用" aria-label="Permalink to &quot;一、社会基本矛盾在社会发展中的作用&quot;">​</a></h3><ol><li>社会基本矛盾在社会发展中的作用 <ul><li>生产力和生产关系的矛盾</li><li>上层建筑和经济基础的矛盾</li></ul></li><li>两对社会基本矛盾之间的关系 <ul><li><code>相互制约，有主次之分</code></li></ul></li><li>社会基本矛盾是社会发展的基本动力</li></ol><h3 id="二、阶级斗争在阶级社会发展中的作用" tabindex="-1">二、阶级斗争在阶级社会发展中的作用 <a class="header-anchor" href="#二、阶级斗争在阶级社会发展中的作用" aria-label="Permalink to &quot;二、阶级斗争在阶级社会发展中的作用&quot;">​</a></h3><ol><li>阶级的产生和实质<br> 阶级是一个历史范畴，它不是从来就有的，也不会永远存在下去。阶级是生产发展到一定阶段的产物。<br> 阶级的本质：阶级就是在以生产资料私有制为 <ul><li>划分阶级的唯一是经济标准</li><li>阶级不仅仅是一个经济范畴，而且是一个更广泛的社会范畴。</li></ul></li><li>阶级斗争是阶级社会发展的直接动力<br> 阶级产生的根本前提是由于生产力发展而出现剩余产品。 阶级斗争是阶级社会发展的直接动力。 物质利益的对立是阶级斗争的根源。</li><li>社会革命及其在社会发展中的作用<br> 社会革命是阶级斗争的最高表现，是指夺取国家政权的斗争。进步的革命的阶级反对反动统治阶级的国家政权的斗争，才是社会革命。<br> 社会革命最深刻的根源，是社会基本矛盾。<br> 马克思说“革命是历史的火车头”。说明了社会革命在社会发展中的重大作用。</li></ol><ul><li>[选择题]阶级斗争的根源在于<code>物质利益的对立</code></li><li>[选择题]划分阶级所依据的根本标准是各社会集团的<code>经济地位</code></li></ul><h3 id="三、革命和改革社会发展中的作用" tabindex="-1">三、革命和改革社会发展中的作用 <a class="header-anchor" href="#三、革命和改革社会发展中的作用" aria-label="Permalink to &quot;三、革命和改革社会发展中的作用&quot;">​</a></h3><ol><li>社会改革及其在社会发展中的作用<br> 在一定社会制度下，为了解决生产关系不适合生产力、上层建筑不适合经济基础，而进行的。</li><li>社会主义社会的改革<br> 社会改革推动社会的发展</li></ol><p>[选择题]关于社会改革的说法正确的是<code>社会改革是社会体制的改善和革新</code></p><h2 id="第三节、人民群众在历史发展中的作用" tabindex="-1">第三节、人民群众在历史发展中的作用 <a class="header-anchor" href="#第三节、人民群众在历史发展中的作用" aria-label="Permalink to &quot;第三节、人民群众在历史发展中的作用&quot;">​</a></h2><ol><li>人的本质和人与社会的关系 <ul><li>人性和人的本质 <ul><li>1.劳动是人的本质</li><li>2.<code>人的本质是一切社会关系的总和</code></li><li>3.人的需要即人的本质</li></ul></li><li>人与社会的关系</li></ul></li><li>人民群众是历史的创造者 <ul><li>历史观上两种根本对立的观点</li><li>人民群众在历史上的作用</li><li>无产阶级政党的群众观点和群众路线 <ul><li>1.群众观点是马克思主义政党的根本观点</li><li>2.群众路线是党的根本工作路线</li></ul></li></ul></li><li>个人在历史发展中的作用 <ul><li>普通个人和历史人物</li><li>杰出人物在历史上的作用</li><li>无产阶级领袖的历史作用</li></ul></li></ol><ul><li>[选择题]区分普通人物和历史人物，主要是看他们<code>历史作用的大小</code></li><li>[选择题]正确认识和评价杰出人物的历史作用，一要坚持历史主义的原则，而要坚持<code>阶级分析</code></li><li>[选择题]人的本质在于<code>人的社会属性</code></li><li>[选择题]唯心主义在历史创造者问题上的根本错误在于<code>否认广大人民群众是推动历史发展的决定力量</code></li><li>经济社会形态：<code>原始社会、奴隶社会、封建社会、资本主义社会、共产主义社会</code></li><li>技术社会形态：<code>渔猎社会、农业社会、工业社会、信息社会</code></li><li>[选择题]群众路线的基本出发点和最终归宿是<code>一切为了群众</code></li><li>[选择题]暴力革命是社会革命的<code>基本形式</code></li></ul>',25)])])}const m=i(r,[["render",u]]);export{b as __pageData,m as default};
